import{_ as a,o as e,c as t,j as p,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"忏悔 赤瞳","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/6.套装/忏悔 赤瞳.md","filePath":"4.资源分区/7.物品与装备/6.套装/忏悔 赤瞳.md"}'),b={name:"4.资源分区/7.物品与装备/6.套装/忏悔 赤瞳.md"};function o(d,r,_,l,i,c){return e(),t("div",null,[...r[0]||(r[0]=[p("h1",{id:"忏悔-赤瞳",tabindex:"-1"},[n("忏悔 赤瞳 "),p("a",{class:"header-anchor",href:"#忏悔-赤瞳","aria-label":'Permalink to "忏悔 赤瞳"'},"​")],-1),p("table",{class:"bannerparthead"},[p("tbody",null,[p("tr",{id:"hdr"},[p("td",{class:"runninghead",nowrap:""},"TMD：新世短歌037")])])],-1),s('<h1 id="忏悔-赤瞳-1" tabindex="-1">忏悔&amp;赤瞳 <a class="header-anchor" href="#忏悔-赤瞳-1" aria-label="Permalink to &quot;忏悔&amp;赤瞳&quot;">​</a></h1><p>忏悔&amp;赤瞳</p><p>武器：<br> 忏悔<br> D+500<br> 唯有理解才能获取知识。</p><p>通过对这个异想体的细心观测，我们成功提取出了它的核心并将其塑造成一把武器。</p><p>空洞的眼窝凝视着人们的灵魂，荆棘之冠倾诉着人们的罪孽。</p><p>要想使用这把武器，你必须抱有为了更大的良善而杀戮的决心。</p><p>这把武器虽然不像其他装备那般强大，但它能为持有者提供心灵上的慰藉。</p><p>然而，对于那些缺乏正义的人而言，并不存在什么慰藉。</p><p>该武器为一把武器伤害为6L的长棍，从外观上看，该武器呈现为中心安装有一个骷髅头的十字架，</p><p>该武器具有【长柄】【格挡3】【法破】效果，该武器造成精神伤害，力量需求为3，以该武器格挡时，获得的防御不为格挡防御而是洞察防御，</p><p>在使用该武器时，若你当前的决心属性大于等于6，那么每次攻击结束时，都会获得1层【忏悔】。</p><p>赤瞳<br> C+1000<br> 在这座长有许多眼睛的蜘蛛巢中，爬着许多饥肠辘辘却不知满足的后代。</p><p>为了在夜间觅食，它的眼睛会发出微光。</p><p>这把E.G.O武器可以增强持有者的追踪能力。</p><p>它能在黑暗中察觉到受害者身上的热量所散发出的红光。</p><p>但是，如果持有者注视着蜘眼过久，他们反会被其操控。</p><p>这是一把武器伤害为11L的长棍，该武器上长有赤红的眼眸，请勿长时间凝视，</p><p>该武器具有【长柄】【格挡1】【9加骰】效果，该武器造成钝击伤害，力量需求为3，</p><p>特殊的，该武器也能改为以刀类武器购买，此时该武器更名为《赤瞳（开）》，造成的伤害类型更改为挥砍伤害，</p><p>在使用该武器时，每次进行攻击，都会为你提供1层【赤瞳】效果，</p><p>若使用者当前的耐力属性大于等于11，则在进入战斗时开始，赤瞳的使用者会获得耐力上的传奇属性*5M的移动速度。</p><p>护甲：<br> 赤瞳<br> C+1500<br> 蜘蛛巢的狩猎本能是无法被压制的。</p><p>即使在黑暗中，它的眼睛也能死死咬住目标。</p><p>这件E.G.O护甲能增强穿戴者的体能，</p><p>可也会使他们变得残忍，对朋友和敌人毫无怜悯。</p><p>但是，如果穿戴者注视着蜘眼过久，他们反会被其操控。</p><p>该护甲为一件外观上纹有大量红色眼眸的礼服，其在分类上为轻甲，提供11/11点洞察防御，</p><p>若穿戴者当前的耐力属性大于等于11，则在进入战斗时开始，赤瞳的使用者会获得耐力上的传奇属性*5M的移动速度。</p><p>穿戴者在力量检定上获得等同于耐力上的传奇属性*1点增强加值，</p><p>在受到攻击时，如果你的洞察防御仍有保留，则此次攻击具有劣化1。</p><p>套装效果：<br> 忏悔&amp;赤瞳<br> C+1000<br> 前置条件：【集齐武器：忏悔，赤瞳或赤瞳（开），护甲：赤瞳】<br> 如果没有饥渴便无法与那赤瞳对视，若没有为了行善而见血的决心便无法挥舞忏悔，</p><p>那么为了生存所犯下的罪是否能原谅？</p><p>人们有时会歪曲事实来为自己的某些过错进行辩解，可他们一旦这么做，那就不再是忏悔了。</p><p>效果：<br> 现在每次攻击结束后，额外获得2层【忏悔】和【赤瞳】，每轮开始时获得仅能用于释放该技艺的2AP，</p><p>现在你可以将忏悔&amp;赤瞳中没有参与攻击的武器的一半基础数值和全部特性加入攻击，并且一场景一次，你可以将忏悔的武器伤害转为在格挡时生效的洞察防御，持续一场景，</p><p>以一个标准动作消耗2点意志力使用，若当前的【忏悔】+【赤瞳】层数均低于10层，则这次攻击的加骰上升一级（最高8加骰），且这次攻击具有【能量武器】，</p><p>若当前的【忏悔】+【赤瞳】层数均大于10层，则使用强化版的该技艺，这次攻击的加骰上升一级（最高8加骰），且这次攻击具有【能量武器】，这次攻击命中时，敌人需要以强韧豁免对抗DC17，失败则承受差值流血异常点数，最多1点，失去所有的【忏悔】和【赤瞳】，每失去7层【忏悔】就在本次攻击结束后为自己恢复2点完好（附带24医疗点），每失去6层【赤瞳】就使固定DC上升4点，最多承受的流血异常点数增加3点。</p><p>——额外支付C+2000，将该技艺差升至B级，</p><p>该技艺的效果升级为：</p><p>以一个标准动作消耗2点意志力使用，若当前的【忏悔】+【赤瞳】层数均低于10层，则这次攻击的加骰上升一级（最高8加骰），且这次攻击具有【能量武器】，且这次攻击的检定出目增加一半，</p><p>若当前的【忏悔】+【赤瞳】层数均大于10层，则使用强化版的该技艺，这次攻击的加骰上升一级（最高8加骰），且这次攻击具有【能量武器】，且这次攻击的检定出目增加一半，这次攻击命中时，敌人需要以强韧豁免对抗DC25，失败则承受差值流血异常点数，最多1点，失去所有的【忏悔】和【赤瞳】，每失去7层【忏悔】就在本次攻击结束后为自己恢复2点完好（附带24医疗点），每失去6层【赤瞳】就使固定DC上升4点，最多承受的流血异常点数增加3点。</p><p>饰品：<br> 忏悔<br> D+500<br> 占据头盔位</p><p>仅是承受苦难，便可洗刷一半罪孽。</p><p>荆棘之冠会保护人们的灵魂。</p><p>荆棘带来的刺痛是短暂的，但它时刻警示着自己。</p><p>然而，对于那些毫无负罪感的人而言，他们不会从这件饰品中获得丝毫的益处。</p><p>对于声望为负的单位，该饰品不会有任何效果，</p><p>该饰品外观为一圈荆棘冠，佩戴者不会感受到疼痛，且会感受到宁静与祥和，</p><p>持有者每次攻击结束时额外获得1层【忏悔】，</p><p>以忏悔发动的攻击可以任意留手，你现在可以在长休期间进行忏悔，若如此做，则长休时间减半，<br> 在使用忏悔&amp;赤瞳时，消耗的意志力减少1点。</p><p>赤瞳<br> C+1000<br> 占据护符位<br> 这个异想体不会立即杀死它的猎物，因为它要确保猎物尽可能久地保持新鲜。</p><p>它分泌的毒液中含有一种特殊的毒素，会永久性地损害心脏，最终导致死亡。</p><p>被困在茧中的员工别无选择，只能在一片漆黑中迎来自己的末日，听着自己的心跳一天比一天慢。</p><p>该饰品外观为佩戴在脸上的眼镜，</p><p>持有者每次攻击结束时额外获得1层【赤瞳】，</p><p>在使用忏悔&amp;赤瞳时，消耗的意志力减少1点，</p><p>在穿戴赤瞳护甲时，获得基于洞察防御的【适应】，</p><p>额外获得感知属性与沉着属性较低者上的附加成功*2+1点洞察防御。</p><p>套装效果：<br> 集齐赤瞳饰品与忏悔饰品时，赤瞳武器获得谐振，且谐振获得的防御类型固定为洞察防御，赤瞳护甲额外获得基于洞察防御的坚韧。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',61)])])}const f=a(b,[["render",o]]);export{m as __pageData,f as default};
